@startuml
class "Settings" {
  [C]
  □ key
  □ value
}

class "InputSensor" {
  [C]
  □ name
  □ temperature
  □ humidity
}

class "InputWeatherstation" {
  [C]
  □ name
  □ temperature
  □ humidity
  □ wind_speed
  □ rain_amount
  □ raining
}

class "InputSwitch" {
  [C]
  □ name
  □ image
  □ x
  □ y
  □ width
  □ height
  □ state
}

class "InputSolarpanel" {
  [C]
  □ name
  □ power
}

class "InputWindow" {
  [C]
  □ name
  □ closed
}

class "OutputTrigger" {
  [C]
  □ name
  □ state
}

class "SwitchState" {
  [E]
  □ on
  □ off
  □ auto
}

"InputSwitch" -- "SwitchState"
@enduml
